<template>
  <div class="container mx-auto px-4 py-8 max-w-4xl">
    <h1 class="text-3xl font-bold mb-8">Shopping Cart</h1>
    
    <div v-if="cartItems.length > 0" class="flex flex-col md:flex-row gap-8">
      <!-- Cart Items -->
      <div class="md:w-2/3">
        <div class="bg-white rounded-xl shadow-sm border border-gray-100 p-6 mb-4" v-for="item in cartItems" :key="item.id">
          <div class="flex items-center gap-4">
            <div class="w-24 h-24 bg-gray-100 rounded-lg flex-shrink-0"></div>
            <div class="flex-grow">
              <h3 class="font-semibold text-lg">{{ item.name }}</h3>
              <p class="text-gray-500 text-sm mb-2">{{ item.category }}</p>
              <div class="flex items-center justify-between">
                <span class="font-bold">${{ item.price.toFixed(2) }}</span>
                <div class="flex items-center border rounded-md">
                  <button class="px-3 py-1 hover:bg-gray-50" @click="item.quantity > 1 ? item.quantity-- : null">-</button>
                  <span class="px-3 py-1 border-x text-sm">{{ item.quantity }}</span>
                  <button class="px-3 py-1 hover:bg-gray-50" @click="item.quantity++">+</button>
                </div>
              </div>
            </div>
            <button class="text-gray-400 hover:text-red-500 p-2">
              <Icon name="lucide:trash-2" class="w-5 h-5" />
            </button>
          </div>
        </div>
      </div>

      <!-- Order Summary -->
      <div class="md:w-1/3">
        <div class="bg-gray-50 rounded-xl p-6 sticky top-24">
          <h2 class="text-xl font-bold mb-4">Order Summary</h2>
          <div class="space-y-3 text-sm mb-4">
            <div class="flex justify-between">
              <span class="text-gray-600">Subtotal</span>
              <span class="font-semibold">${{ subtotal.toFixed(2) }}</span>
            </div>
            <div class="flex justify-between">
              <span class="text-gray-600">Shipping</span>
              <span class="font-semibold">Calculated at checkout</span>
            </div>
          </div>
          <div class="border-t pt-4 mb-6">
            <div class="flex justify-between items-center text-lg">
              <span class="font-bold">Total</span>
              <span class="font-bold">${{ subtotal.toFixed(2) }}</span>
            </div>
          </div>
          <button class="w-full bg-blue-600 text-white py-3 rounded-lg font-semibold hover:bg-blue-700 transition">
            Proceed to Checkout
          </button>
        </div>
      </div>
    </div>

    <!-- Empty Cart -->
    <div v-else class="text-center py-20 bg-gray-50 rounded-2xl">
      <Icon name="lucide:shopping-cart" class="w-16 h-16 mx-auto text-gray-300 mb-4" />
      <h2 class="text-2xl font-bold mb-2">Your cart is empty</h2>
      <p class="text-gray-500 mb-6">Looks like you haven't added any items yet.</p>
      <NuxtLink to="/products" class="inline-block bg-blue-600 text-white px-8 py-3 rounded-lg font-semibold hover:bg-blue-700 transition">
        Start Shopping
      </NuxtLink>
    </div>
  </div>
</template>

<script setup>
import { ref, computed } from 'vue'

// Dummy data for cart items
const cartItems = ref([
  { id: 1, name: 'Premium Cotton T-Shirt', category: 'Men\'s Clothing', price: 35.00, quantity: 2 },
  { id: 2, name: 'Minimalist Watch', category: 'Accessories', price: 120.00, quantity: 1 }
])

const subtotal = computed(() => {
  return cartItems.value.reduce((total, item) => total + (item.price * item.quantity), 0)
})
</script>
